// RotateBotToken is the resolver for the rotateBotToken field.
func (r *mutationResolver) RotateBotToken(ctx context.Context, id string) (string, error) {
	authID := middleware.GetUserID(ctx)
	if authID == "" {
		return "", errors.New("unauthorized")
	}

	_, rawID, err := helpers.DecodeGlobalID(id)
	if err != nil {
		rawID = id
	}

	botUUID, err := uuid.Parse(rawID)
	if err != nil {
		return "", errors.New("invalid bot id")
	}

	bot, err := r.Store.GetUserByID(ctx, botUUID)
	if err != nil {
		return "", errors.New("bot not found")
	}

	if !bot.BotOwnerID.Valid || bot.BotOwnerID.UUID.String() != authID {
		return "", errors.New("access denied: you are not the owner")
	}

	resp, err := r.AuthClient.CreateBotToken(ctx, &authv1.CreateBotTokenRequest{
		BotId: rawID,
	})
	if err != nil {
		return "", fmt.Errorf("failed to rotate token: %w", err)
	}

	return resp.AccessToken, nil
}

// Node is the resolver for the node field.
func (r *queryResolver) Node(ctx context.Context, id string) (model.Node, error) {
	kind, uuidStr, err := helpers.DecodeGlobalID(id)
	if err != nil {
		return nil, errors.New("invalid node id")
	}

	switch kind {
	case "User":
		return loaders.LoadUser(ctx, uuidStr)
	case "Chat":
		authID := middleware.GetUserID(ctx)
		if authID == "" {
			return nil, errors.New("unauthorized")
		}
		resp, err := r.ChatClient.GetChat(ctx, &chatv1.GetChatRequest{
			ChatId: &uuidStr,
			UserId: authID,
		})
		if err != nil {
			return nil, helpers.MapGRPCError(err)
		}

		// Убираем r.Store, оставляем только (ctx, authID, pbChat)
		return r.Enricher.EnrichChat(ctx, authID, resp.Chat)
	default:
		return nil, fmt.Errorf("unsupported node type: %s", kind)
	}
}

