// DisplayName is the resolver for the displayName field.
func (r *userResolver) DisplayName(ctx context.Context, obj *dbgen.User) (*string, error) {
	u, err := loaders.LoadUser(ctx, obj.ID.String())
	if err != nil {
		name := obj.FirstName
		return &name, nil
	}
	full := u.FirstName
	if u.LastName.Valid && u.LastName.String != "" {
		full += " " + u.LastName.String
	}
	return &full, nil
}

